function Hero() {
  return (
    <section style={{
      backgroundImage: "url('https://source.unsplash.com/1600x600/?resort')",
      backgroundSize: "cover",
      color: "white",
      height: "400px",
      display: "flex",
      flexDirection: "column",
      justifyContent: "center"
    }}>
      <h1>Welcome to Sunset Resort</h1>
      <p>Luxury stay with nature views</p>
      <button>Book Now</button>
    </section>
  );
}

export default Hero;
